7	export function nextGeneration(cells: [number, number][]): [number, number][] {
8	  const isAlive = (x: number, y: number) =>
9	    cells.some(([cx, cy]) => cx === x && cy === y);
10	
11	  const countLiveNeighbors = (x: number, y: number): number =>
12	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
13	
14	  return cells.filter(([x, y]) => {
15	    const neighbors = countLiveNeighbors(x, y);
16	    return neighbors === 2 || neighbors === 3;
17	  });
18	}
